CREATE PROC [dbo].[TR_TONGHOP_THANHPHAM_XUAT2]
(
	@fromDate date,
	@toDate date,
	@tongsokhoi decimal(18, 5) OUT,
	@tongsoluong int OUT
)
AS
BEGIN
	--DECLARE @prev_Date date = DATEADD(M, -6, @currentDate);

	--DECLARE @firstDayOfMonth date = DATEFROMPARTS(YEAR(@prev_Date), MONTH(@prev_Date), 1);
	--DECLARE @lastDayOfMonth date = EOMONTH(@currentDate);

	SELECT A.ORDER_ID, SUM(A.QTY) AS QTY
	INTO #BANGTAM
	FROM tr_phieuxuat_thanhpham A
	WHERE A.ACTIVE = 1
		AND OUT_DATE >= @fromDate
		AND OUT_DATE <= @toDate
	GROUP BY A.ORDER_ID

	SELECT @tongsokhoi = SUM(IIF(A.QTY > B.order_qty, B.order_qty, A.QTY) * ISNULL(C.m3_tc, 0)), 
		@tongsoluong = SUM(IIF(A.QTY > B.order_qty, B.order_qty, A.QTY))
	FROM #BANGTAM A
		INNER JOIN tr_order_detail B ON A.ORDER_ID = B.id
		INNER JOIN tr_sanpham C ON B.item_number = C.masp

	DROP TABLE #BANGTAM;
END
